# v21: The utility-script's mamba_ssm (Mamba3, needed by Nemotron) imports cutlass.cute.
# That cutlass is in the utility-script's nvidia_cutlass_dsl/python_packages/.
# So we MUST addsitedir for cutlass — but only for cutlass, not the broken triton bin.
# We also keep the ptxas chmod fix from v17 as defense for RTX Pro 6000 sm_120.
import os, sys, glob, shutil, stat, site, subprocess, importlib

# (1) Add cutlass DSL to sys.path (this is what Nemotron's Mamba3 imports)
CUTLASS_DSL = '/kaggle/usr/lib/notebooks/ryanholbrook/nvidia-utility-script/nvidia_cutlass_dsl/python_packages/'
if os.path.isdir(CUTLASS_DSL):
    site.addsitedir(CUTLASS_DSL)
    print(f'added cutlass dsl: {CUTLASS_DSL}')
else:
    print(f'WARN: cutlass dsl not found at {CUTLASS_DSL}')

# (2) Defensive chmod fix for ptxas-blackwell (RTX Pro 6000 sm_120 needs it; T4 doesnt)
patched = []
for nm in ('ptxas-blackwell','ptxas-hopper','ptxas-ada','ptxas'):
    for src in glob.glob(f'/kaggle/usr/lib/notebooks/**/triton/backends/nvidia/bin/{nm}', recursive=True):
        dst = f'/tmp/triton_bin/{os.path.basename(src)}'
        os.makedirs(os.path.dirname(dst), exist_ok=True)
        if not os.path.exists(dst):
            try:
                shutil.copy(src, dst); os.chmod(dst, 0o755); patched.append(os.path.basename(src))
            except Exception as e:
                print(f'  chmod skip {src}: {e}')
if patched:
    os.environ['PATH'] = '/tmp/triton_bin:' + os.environ.get('PATH','')
    print(f'patched triton binaries: {patched}')

# (3) Verify mamba_ssm imports (it pulls Mamba3 -> cutlass.cute on its own)
try:
    import mamba_ssm
    print(f'mamba_ssm OK: {mamba_ssm.__file__}')
except Exception as e:
    print(f'mamba_ssm FAIL: {e}')

# (4) bitsandbytes (NOT in utility-script; only needed if 4-bit/T4 path)
try:
    import bitsandbytes
    print(f'bitsandbytes OK: {bitsandbytes.__version__}')
except ImportError:
    print('installing bitsandbytes...')
    r = subprocess.run([sys.executable,'-m','pip','install','-q','-U','bitsandbytes>=0.46.1'], capture_output=True, text=True)
    if r.returncode == 0:
        importlib.invalidate_caches()
        import bitsandbytes
        print(f'bitsandbytes INSTALLED: {bitsandbytes.__version__}')
    else:
        print(f'bitsandbytes install rc={r.returncode}: {r.stderr[-500:]}')
